     1→/**
     2→ * PuzzleGame - Pure jigsaw puzzle logic with canvas rendering.
     3→ * Zero dependency on gesture or input layer.
     4→ */
     5→class PuzzleGame {
     6→  /**
     7→   * @param {string} canvasId - ID of the canvas element
     8→   * @param {number} gridSize - Number of rows/columns (e.g. 4 = 4x4 = 16 pieces)
     9→   */
    10→  constructor(canvasId, gridSize = 4) {
    11→    this.canvas = document.getElementById(canvasId);
    12→    this.ctx = this.canvas.getContext('2d');
    13→    this.gridSize = gridSize;
    14→    this.pieces = [];
    15→    this.selectedPiece = null;
    16→    this.offsetX = 0;
    17→    this.offsetY = 0;
    18→    this.image = null;
    19→    this.imageLoaded = false;
    20→
    21→    // Puzzle target area (centered region where completed puzzle sits)
    22→    this.targetArea = { x: 0, y: 0, w: 0, h: 0 };
    23→
    24→    // Piece dimensions
    25→    this.pieceW = 0;
    26→    this.pieceH = 0;
    27→
    28→    // Game state
    29→    this.moves = 0;
    30→    this.startTime = null;
    31→    this.elapsed = 0;
    32→    this.timerInterval = null;
    33→    this.won = false;
    34→    this.snappedCount = 0;
    35→
    36→    // Snap threshold in pixels
    37→    this.snapThreshold = 30;
    38→
    39→    // Callbacks
    40→    this.onStateChange = null;
    41→    this.onWin = null;
    42→
    43→    // Animation
    44→    this._animFrameId = null;
    45→    this._render = this._renderLoop.bind(this);
    46→  }
    47→
    48→  /**
    49→   * Load an image and initialize the puzzle.
    50→   * @param {string} url - Image URL or base64 data URI
    51→   * @returns {Promise<void>}
    52→   */
    53→  loadImage(url) {
    54→    return new Promise((resolve, reject) => {
    55→      const img = new Image();
    56→      img.crossOrigin = 'anonymous';
    57→      img.onload = () => {
    58→        this.image = img;
    59→        this.imageLoaded = true;
    60→        this._initPuzzle();
    61→        resolve();
    62→      };
    63→      img.onerror = () => reject(new Error('Failed to load image'));
    64→      img.src = url;
    65→    });
    66→  }
    67→
    68→  /** Calculate layout and create pieces. */
    69→  _initPuzzle() {
    70→    const cw = this.canvas.width;
    71→    const ch = this.canvas.height;
    72→
    73→    // Fit image into ~60% of canvas width, centered
    74→    const maxW = cw * 0.55;
    75→    const maxH = ch * 0.85;
    76→    const imgAspect = this.image.width / this.image.height;
    77→    let targetW, targetH;
    78→
    79→    if (imgAspect > maxW / maxH) {
    80→      targetW = maxW;
    81→      targetH = maxW / imgAspect;
    82→    } else {
    83→      targetH = maxH;
    84→      targetW = maxH * imgAspect;
    85→    }
    86→
    87→    this.targetArea = {
    88→      x: (cw - targetW) / 2,
    89→      y: (ch - targetH) / 2,
    90→      w: targetW,
    91→      h: targetH,
    92→    };
    93→
    94→    this.pieceW = targetW / this.gridSize;
    95→    this.pieceH = targetH / this.gridSize;
    96→
    97→    this.createPieces();
    98→    this.shufflePieces();
    99→    this._resetState();
   100→    this._startRenderLoop();
   101→  }
   102→
   103→  /** Create piece objects with correct source and target positions. */
   104→  createPieces() {
   105→    this.pieces = [];
   106→    const srcW = this.image.width / this.gridSize;
   107→    const srcH = this.image.height / this.gridSize;
   108→
   109→    for (let row = 0; row < this.gridSize; row++) {
   110→      for (let col = 0; col < this.gridSize; col++) {
   111→        this.pieces.push({
   112→          id: row * this.gridSize + col,
   113→          row,
   114→          col,
   115→          // Source rectangle in the original image
   116→          sx: col * srcW,
   117→          sy: row * srcH,
   118→          sw: srcW,
   119→          sh: srcH,
   120→          // Current position on canvas
   121→          x: 0,
   122→          y: 0,
   123→          // Correct target position on canvas
   124→          targetX: this.targetArea.x + col * this.pieceW,
   125→          targetY: this.targetArea.y + row * this.pieceH,
   126→          // Rotation in 90-degree increments (0, 1, 2, 3)
   127→          rotation: 0,
   128→          // Whether snapped into correct position
   129→          snapped: false,
   130→        });
   131→      }
   132→    }
   133→  }
   134→
   135→  /** Scatter pieces randomly around the canvas. */
   136→  shufflePieces() {
   137→    const cw = this.canvas.width;
   138→    const ch = this.canvas.height;
   139→    const margin = 10;
   140→
   141→    for (const piece of this.pieces) {
   142→      piece.snapped = false;
   143→      piece.rotation = 0;
   144→      // Random position within canvas bounds
   145→      piece.x = margin + Math.random() * (cw - this.pieceW - margin * 2);
   146→      piece.y = margin + Math.random() * (ch - this.pieceH - margin * 2);
   147→    }
   148→
   149→    // Shuffle draw order
   150→    for (let i = this.pieces.length - 1; i > 0; i--) {
   151→      const j = Math.floor(Math.random() * (i + 1));
   152→      [this.pieces[i], this.pieces[j]] = [this.pieces[j], this.pieces[i]];
   153→    }
   154→
   155→    this.snappedCount = 0;
   156→  }
   157→
   158→  /** Reset game state counters. */
   159→  _resetState() {
   160→    this.moves = 0;
   161→    this.won = false;
   162→    this.snappedCount = 0;
   163→    this.elapsed = 0;
   164→    this.startTime = null;
   165→    if (this.timerInterval) clearInterval(this.timerInterval);
   166→    this.timerInterval = null;
   167→    this._emitState();
   168→  }
   169→
   170→  /** Start the game timer on first interaction. */
   171→  _ensureTimerStarted() {
   172→    if (this.startTime) return;
   173→    this.startTime = Date.now();
   174→    this.timerInterval = setInterval(() => {
   175→      this.elapsed = Math.floor((Date.now() - this.startTime) / 1000);
   176→      this._emitState();
   177→    }, 500);
   178→  }
   179→
   180→  /**
   181→   * Find the topmost non-snapped piece at canvas coordinates.
   182→   * @param {number} x
   183→   * @param {number} y
   184→   * @returns {object|null}
   185→   */
   186→  selectPiece(x, y) {
