   188→    // Iterate from top (end of array) to bottom
   189→    for (let i = this.pieces.length - 1; i >= 0; i--) {
   190→      const p = this.pieces[i];
   191→      if (p.snapped) continue;
   192→      if (x >= p.x && x <= p.x + this.pieceW && y >= p.y && y <= p.y + this.pieceH) {
