   203→  }
   204→
   205→  /**
   206→   * Move the currently selected piece to a position.
   207→   * @param {number} x - Canvas x (cursor position)
   208→   * @param {number} y - Canvas y (cursor position)
   209→   */
   210→  movePiece(x, y) {
