   319→  /** Draw everything on the canvas. */
   320→  _draw() {
   321→    const ctx = this.ctx;
   322→    const cw = this.canvas.width;
   323→    const ch = this.canvas.height;
   324→
   325→    // Clear
   326→    ctx.clearRect(0, 0, cw, ch);
   327→
   328→    // Background
