   414→    // Reset shadow before drawing border
   415→    ctx.shadowColor = 'transparent';
   416→    ctx.shadowBlur = 0;
   417→    ctx.shadowOffsetX = 0;
   418→    ctx.shadowOffsetY = 0;
   419→
   420→    // Border
