   422→      ctx.strokeStyle = 'rgba(204, 255, 0, 0.4)';
   423→      ctx.lineWidth = 2;
   424→    } else if (piece === this.selectedPiece) {
   425→      ctx.strokeStyle = 'rgba(204, 255, 0, 0.9)';
   426→      ctx.lineWidth = 3;
   427→    } else {
   428→      ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
   429→      ctx.lineWidth = 1.5;
   430→    }
   431→    ctx.strokeRect(0, 0, pw, ph);
   432→
   433→    ctx.restore();
   434→  }
