   457→  resize(width, height) {
   458→    this.canvas.width = width;
   459→    this.canvas.height = height;
   460→    if (this.imageLoaded) {
   461→      // Recalculate target area and piece positions
   462→      const oldTarget = { ...this.targetArea };
   463→      const cw = width;
   464→      const ch = height;
   465→      const maxW = cw * 0.55;
   466→      const maxH = ch * 0.85;
   467→      const imgAspect = this.image.width / this.image.height;
   468→      let targetW, targetH;
   469→      if (imgAspect > maxW / maxH) {
   470→        targetW = maxW;
   471→        targetH = maxW / imgAspect;
   472→      } else {
   473→        targetH = maxH;
   474→        targetW = maxH * imgAspect;
   475→      }
   476→
   477→      const newTarget = {
   478→        x: (cw - targetW) / 2,
   479→        y: (ch - targetH) / 2,
   480→        w: targetW,
   481→        h: targetH,
   482→      };
   483→
   484→      const scaleX = newTarget.w / oldTarget.w;
   485→      const scaleY = newTarget.h / oldTarget.h;
   486→
   487→      this.targetArea = newTarget;
   488→      this.pieceW = targetW / this.gridSize;
   489→      this.pieceH = targetH / this.gridSize;
   490→
   491→      // Reposition pieces proportionally
   492→      for (const p of this.pieces) {
   493→        p.targetX = newTarget.x + p.col * this.pieceW;
   494→        p.targetY = newTarget.y + p.row * this.pieceH;
   495→        if (p.snapped) {
   496→          p.x = p.targetX;
   497→          p.y = p.targetY;
   498→        } else {
   499→          // Scale position relative to old canvas
   500→          p.x = (p.x / (oldTarget.w / scaleX + (cw / scaleX - oldTarget.w / scaleX))) * cw;
   501→          p.y = (p.y / (oldTarget.h / scaleY + (ch / scaleY - oldTarget.h / scaleY))) * ch;
   502→          p.x = Math.max(0, Math.min(cw - this.pieceW, p.x));
   503→          p.y = Math.max(0, Math.min(ch - this.pieceH, p.y));
   504→        }
   505→      }
   506→    }
   507→  }
   508→
   509→  /** Clean up resources. */
   510→  destroy() {
   511→    if (this._animFrameId) cancelAnimationFrame(this._animFrameId);
   512→    if (this.timerInterval) clearInterval(this.timerInterval);
   513→  }
   514→}
