   309→  function handleGesture(gesture, confidence, handPos) {
   310→    if (!game || game.won) return;
   311→
   312→    // Update webcam bar UI
   313→    const labels = {
   314→      pinch: 'pinch',
   315→      fist: 'fist',
   316→      open_hand: 'open',
   317→      frame: 'frame',
   318→      none: 'none',
   319→    };
   320→    gestureEl.textContent = labels[gesture] || gesture;
   321→    confidenceEl.textContent = Math.round(confidence * 100) + '%';
   322→
   323→    if (!handPos) return;
   324→
   325→    // Convert normalized hand position to canvas coordinates
   326→    const rawX = handPos.x * gameCanvas.width;
   327→    const rawY = handPos.y * gameCanvas.height;
   328→
   329→    // Smooth cursor with lerp
   330→    if (!cursorInitialized) {
   331→      smoothCursor.x = rawX;
   332→      smoothCursor.y = rawY;
   333→      cursorInitialized = true;
   334→    } else {
   335→      smoothCursor.x += (rawX - smoothCursor.x) * LERP;
   336→      smoothCursor.y += (rawY - smoothCursor.y) * LERP;
   337→    }
