   364→        }
   365→        break;
   366→
   367→      case 'frame':
   368→        if (gestureState.lastGesture !== 'frame') {
   369→          takeSnapshot();
   370→        }
   371→        break;
   372→    }
   373→
   374→    gestureState.lastGesture = gesture;
   375→  }
