    97→    } catch (e) {
    98→      console.warn('ONNX session failed to load, falling back to heuristic:', e);
    99→      this.session = null;
   100→    }
   101→  }
   102→
   103→  /** Dynamically import the MediaPipe vision module. */
   104→  async _loadMediaPipe() {
   105→    // Use dynamic import from CDN
   106→    const module = await import(
   107→      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest'
   108→    );
   109→    return module;
   110→  }
   111→
   112→  /** Start webcam stream. */
