/**
 * main.js - Entry point. Connects SlidingPuzzleGame with GestureController
 * and manages leaderboard + UI.
 */
(function () {
  'use strict';

  // ---------------------------------------------------------------
  // Leaderboard (localStorage)
  // ---------------------------------------------------------------
  const LEADERBOARD_KEY = 'sliding-puzzle-leaderboard';
  const MAX_ENTRIES = 20;

  function loadLeaderboard() {
    try {
      const data = localStorage.getItem(LEADERBOARD_KEY);
      return data ? JSON.parse(data) : [];
    } catch {
      return [];
    }
  }

  function saveLeaderboard(entries) {
    localStorage.setItem(LEADERBOARD_KEY, JSON.stringify(entries));
  }

  function addLeaderboardEntry(name, time, moves, gridSize) {
    const entries = loadLeaderboard();
    entries.push({ name, time, moves, gridSize, date: Date.now() });
    entries.sort((a, b) => a.time - b.time || a.moves - b.moves);
    const trimmed = entries.slice(0, MAX_ENTRIES);
    saveLeaderboard(trimmed);
    return trimmed;
  }

  function formatTime(seconds) {
    const m = Math.floor(seconds / 60).toString().padStart(2, '0');
    const s = (seconds % 60).toString().padStart(2, '0');
    return m + ':' + s;
  }

  // ---------------------------------------------------------------
  // Sample image generator
  // ---------------------------------------------------------------
  function generateSampleImage() {
    const c = document.createElement('canvas');
    c.width = 400;
    c.height = 400;
    const ctx = c.getContext('2d');

    const g1 = ctx.createLinearGradient(0, 0, 400, 400);
    g1.addColorStop(0, '#ff6b6b');
    g1.addColorStop(0.25, '#feca57');
    g1.addColorStop(0.5, '#48dbfb');
    g1.addColorStop(0.75, '#ff9ff3');
    g1.addColorStop(1, '#54a0ff');
    ctx.fillStyle = g1;
    ctx.fillRect(0, 0, 400, 400);

    ctx.globalAlpha = 0.3;
    const colors = ['#fff', '#2d3436', '#6c5ce7', '#00b894', '#fdcb6e'];
    for (let i = 0; i < 12; i++) {
      ctx.beginPath();
      ctx.arc(
        50 + Math.random() * 300,
        50 + Math.random() * 300,
        15 + Math.random() * 40,
        0,
        Math.PI * 2
      );
      ctx.fillStyle = colors[i % colors.length];
      ctx.fill();
    }

    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 50px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('SLIDE', 200, 170);
    ctx.font = 'bold 36px sans-serif';
    ctx.fillText('PUZZLE', 200, 230);
    ctx.globalAlpha = 1;

    return c.toDataURL('image/png');
  }

  // ---------------------------------------------------------------
  // DOM references
  // ---------------------------------------------------------------
  const gameCanvas = document.getElementById('game-canvas');
  const videoEl = document.getElementById('webcam');
  const overlayCanvas = document.getElementById('webcam-overlay');

  // HUD
  const timerEl = document.getElementById('timer');
  const movesEl = document.getElementById('moves');
  const completionEl = document.getElementById('completion');
  const modeDot = document.getElementById('mode-dot');
  const modeEl = document.getElementById('mode-label');

  // Webcam bar
  const gestureEl = document.getElementById('gesture-label');
  const confidenceEl = document.getElementById('confidence-label');

  // Controls
  const btnNewGame = document.getElementById('btn-new-game');
  const btnCamera = document.getElementById('btn-camera');
  const selectDifficulty = document.getElementById('select-difficulty');
  const btnUpload = document.getElementById('btn-upload');
  const fileInput = document.getElementById('file-input');
  const webcamContainer = document.getElementById('webcam-container');

  // Solved overlay
  const solvedOverlay = document.getElementById('solved-overlay');
  const solvedTimeEl = document.getElementById('solved-time');
  const solvedMovesEl = document.getElementById('solved-moves');
  const btnPlayAgain = document.getElementById('btn-play-again');
  const btnSubmitScore = document.getElementById('btn-submit-score');
  const playerNameInput = document.getElementById('player-name');

  // Leaderboard overlay
  const btnLeaderboard = document.getElementById('btn-leaderboard');
  const leaderboardOverlay = document.getElementById('leaderboard-overlay');
  const leaderboardBody = document.getElementById('leaderboard-body');
  const btnCloseLeaderboard = document.getElementById('btn-close-leaderboard');

  // ---------------------------------------------------------------
  // Canvas sizing
  // ---------------------------------------------------------------
  function resizeCanvas() {
    const container = gameCanvas.parentElement;
    const rect = container.getBoundingClientRect();
    gameCanvas.width = rect.width;
    gameCanvas.height = rect.height;
    if (game && game.imageLoaded) {
      game.resize(rect.width, rect.height);
    }
  }

  // ---------------------------------------------------------------
  // Initialize game
  // ---------------------------------------------------------------
  let game = null;
  let gestureCtrl = null;
  let cameraActive = false;
  let currentImageUrl = null;

  async function initGame(imageUrl, gridSize) {
    if (game) game.destroy();
    solvedOverlay.classList.add('hidden');
    leaderboardOverlay.classList.add('hidden');

    resizeCanvas();

    game = new SlidingPuzzleGame('game-canvas', gridSize || 3);

    game.onStateChange = (state) => {
      timerEl.textContent = formatTime(state.time);
      movesEl.textContent = state.moves;
      completionEl.textContent = state.completion + '%';
    };

    game.onWin = (state) => {
      setTimeout(() => {
        solvedTimeEl.textContent = formatTime(state.time);
        solvedMovesEl.textContent = state.moves;
        solvedOverlay.classList.remove('hidden');

        // Restore saved player name
        const savedName = localStorage.getItem('sliding-puzzle-player-name');
        if (savedName && playerNameInput) {
          playerNameInput.value = savedName;
        }
      }, 400);
    };

    currentImageUrl = imageUrl;
    await game.loadImage(imageUrl);
  }

  // ---------------------------------------------------------------
  // Mouse / Touch controls
  // ---------------------------------------------------------------
  function getCanvasPos(e) {
    const rect = gameCanvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left) * (gameCanvas.width / rect.width),
      y: (e.clientY - rect.top) * (gameCanvas.height / rect.height),
    };
  }

  gameCanvas.addEventListener('click', (e) => {
    if (!game || game.won) return;
    const pos = getCanvasPos(e);
    game.slideTileAt(pos.x, pos.y);
  });

  gameCanvas.addEventListener('mousemove', (e) => {
    if (!game) return;
    const pos = getCanvasPos(e);
    game.setHover(pos.x, pos.y);
  });

  gameCanvas.addEventListener('mouseleave', () => {
    if (game) game.clearHover();
  });

  // Touch support
  gameCanvas.addEventListener(
    'touchend',
    (e) => {
      e.preventDefault();
      if (!game || game.won) return;
      const touch = e.changedTouches[0];
      const pos = getCanvasPos(touch);
      game.slideTileAt(pos.x, pos.y);
    },
    { passive: false }
  );

  // ---------------------------------------------------------------
  // Gesture controller integration
  // ---------------------------------------------------------------
  let gestureState = {
    lastGesture: 'none',
    pinchTriggered: false,
  };

  let smoothCursor = { x: 0, y: 0 };
  let cursorInitialized = false;
  const LERP = 0.25;

  async function startCamera() {
    if (gestureCtrl) {
      gestureCtrl.destroy();
      gestureCtrl = null;
    }

    webcamContainer.classList.remove('hidden');
    btnCamera.textContent = 'Camera Off';

    try {
      gestureCtrl = new GestureController(videoEl, handleGesture);
      gestureCtrl.setOverlayCanvas(overlayCanvas);
      await gestureCtrl.init();
      cameraActive = true;
      modeEl.textContent = 'Gesture';
      modeDot.classList.add('active');
    } catch (err) {
      console.error('Camera init failed:', err);
      cameraActive = false;
      webcamContainer.classList.add('hidden');
      btnCamera.textContent = 'Camera';
      modeEl.textContent = 'Mouse';
      modeDot.classList.remove('active');
    }
  }

  function stopCamera() {
    if (gestureCtrl) {
      gestureCtrl.destroy();
      gestureCtrl = null;
    }
    cameraActive = false;
    webcamContainer.classList.add('hidden');
    btnCamera.textContent = 'Camera';
    modeEl.textContent = 'Mouse';
    modeDot.classList.remove('active');
    gestureState.lastGesture = 'none';
    gestureState.pinchTriggered = false;
    cursorInitialized = false;
  }

  /**
   * Map gestures to game actions.
   * For sliding puzzle: pinch = slide tile at cursor position
   */
  function handleGesture(gesture, confidence, handPos) {
    if (!game || game.won) return;

    // Update webcam bar UI
    const labels = {
      pinch: 'pinch',
      fist: 'fist',
      open_hand: 'open',
      frame: 'frame',
      none: 'none',
    };
    gestureEl.textContent = labels[gesture] || gesture;
    confidenceEl.textContent = Math.round(confidence * 100) + '%';

    if (!handPos) return;

    // Convert normalized hand position to canvas coordinates
    const rawX = handPos.x * gameCanvas.width;
    const rawY = handPos.y * gameCanvas.height;

    // Smooth cursor with lerp
    if (!cursorInitialized) {
      smoothCursor.x = rawX;
      smoothCursor.y = rawY;
      cursorInitialized = true;
    } else {
      smoothCursor.x += (rawX - smoothCursor.x) * LERP;
      smoothCursor.y += (rawY - smoothCursor.y) * LERP;
    }

    const cx = smoothCursor.x;
    const cy = smoothCursor.y;

    // Update hover
    game.setHover(cx, cy);

    switch (gesture) {
      case 'pinch':
        // Slide tile on pinch start (not while held)
        if (!gestureState.pinchTriggered) {
          game.slideTileAt(cx, cy);
          gestureState.pinchTriggered = true;
        }
        break;

      case 'open_hand':
      case 'none':
        gestureState.pinchTriggered = false;
        break;

      case 'fist':
        gestureState.pinchTriggered = false;
        break;
    }

    gestureState.lastGesture = gesture;
  }

  // ---------------------------------------------------------------
  // Leaderboard UI
  // ---------------------------------------------------------------
  function renderLeaderboard() {
    const entries = loadLeaderboard();
    leaderboardBody.innerHTML = '';

    if (entries.length === 0) {
      leaderboardBody.innerHTML =
        '<tr><td colspan="4" class="lb-empty">No records yet. Be the first!</td></tr>';
      return;
    }

    entries.forEach((entry, i) => {
      const tr = document.createElement('tr');
      tr.innerHTML = `
        <td class="lb-rank">#${i + 1}</td>
        <td class="lb-name">${escapeHtml(entry.name)}</td>
        <td class="lb-time">${formatTime(entry.time)}</td>
        <td class="lb-moves">${entry.moves}</td>
      `;
      leaderboardBody.appendChild(tr);
    });
  }

  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  // ---------------------------------------------------------------
  // UI controls
  // ---------------------------------------------------------------
  btnNewGame.addEventListener('click', () => {
    const size = parseInt(selectDifficulty.value, 10) || 3;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnCamera.addEventListener('click', () => {
    if (cameraActive) {
      stopCamera();
    } else {
      startCamera();
    }
  });

  selectDifficulty.addEventListener('change', () => {
    const size = parseInt(selectDifficulty.value, 10) || 3;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnUpload.addEventListener('click', () => {
    fileInput.click();
  });

  fileInput.addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const size = parseInt(selectDifficulty.value, 10) || 3;
      initGame(ev.target.result, size);
    };
    reader.readAsDataURL(file);
  });

  // Solved overlay
  btnPlayAgain.addEventListener('click', () => {
    solvedOverlay.classList.add('hidden');
    const size = parseInt(selectDifficulty.value, 10) || 3;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnSubmitScore.addEventListener('click', () => {
    const name = playerNameInput.value.trim().toUpperCase();
    if (!name || !game) return;

    localStorage.setItem('sliding-puzzle-player-name', name);

    const state = game.getState();
    addLeaderboardEntry(name, state.time, state.moves, state.gridSize);

    solvedOverlay.classList.add('hidden');
    renderLeaderboard();
    leaderboardOverlay.classList.remove('hidden');
  });

  if (playerNameInput) {
    playerNameInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        btnSubmitScore.click();
      }
    });
  }

  // Leaderboard
  btnLeaderboard.addEventListener('click', () => {
    renderLeaderboard();
    leaderboardOverlay.classList.remove('hidden');
  });

  btnCloseLeaderboard.addEventListener('click', () => {
    leaderboardOverlay.classList.add('hidden');
  });

  leaderboardOverlay.addEventListener('click', (e) => {
    if (e.target === leaderboardOverlay) {
      leaderboardOverlay.classList.add('hidden');
    }
  });

  // ---------------------------------------------------------------
  // Window resize handling
  // ---------------------------------------------------------------
  let resizeTimeout;
  window.addEventListener('resize', () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(() => {
      resizeCanvas();
    }, 150);
  });

  // ---------------------------------------------------------------
  // Bootstrap
  // ---------------------------------------------------------------
  const sampleImage = generateSampleImage();
  resizeCanvas();
  initGame(sampleImage, 3);
})();

