    const cx = smoothCursor.x;
    const cy = smoothCursor.y;

    // Update hover
    game.setHover(cx, cy);

    switch (gesture) {
      case 'pinch':
        // Slide tile on pinch start (not while held)
        if (!gestureState.pinchTriggered) {
          game.slideTileAt(cx, cy);
          gestureState.pinchTriggered = true;
        }
        break;

      case 'open_hand':
      case 'none':
        gestureState.pinchTriggered = false;
        break;

      case 'fist':
        gestureState.pinchTriggered = false;
        break;
    }

    gestureState.lastGesture = gesture;
  }

  // ---------------------------------------------------------------
  // Leaderboard UI
  // ---------------------------------------------------------------
  function renderLeaderboard() {
    const entries = loadLeaderboard();
    leaderboardBody.innerHTML = '';

    if (entries.length === 0) {
      leaderboardBody.innerHTML =
        '<tr><td colspan="4" class="lb-empty">No records yet. Be the first!</td></tr>';
      return;
    }

    entries.forEach((entry, i) => {
      const tr = document.createElement('tr');
      tr.innerHTML = `
        <td class="lb-rank">#${i + 1}</td>
        <td class="lb-name">${escapeHtml(entry.name)}</td>
        <td class="lb-time">${formatTime(entry.time)}</td>
        <td class="lb-moves">${entry.moves}</td>
      `;
      leaderboardBody.appendChild(tr);
    });
  }

  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  // ---------------------------------------------------------------
  // UI controls
  // ---------------------------------------------------------------
  btnNewGame.addEventListener('click', () => {
    const size = parseInt(selectDifficulty.value, 10) || 3;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnCamera.addEventListener('click', () => {
    if (cameraActive) {
      stopCamera();
    } else {
      startCamera();
    }
  });

  selectDifficulty.addEventListener('change', () => {
    const size = parseInt(selectDifficulty.value, 10) || 3;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnUpload.addEventListener('click', () => {
    fileInput.click();
  });

  fileInput.addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const size = parseInt(selectDifficulty.value, 10) || 3;
      initGame(ev.target.result, size);
    };
    reader.readAsDataURL(file);
  });

  // Solved overlay
  btnPlayAgain.addEventListener('click', () => {
    solvedOverlay.classList.add('hidden');
    const size = parseInt(selectDifficulty.value, 10) || 3;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnSubmitScore.addEventListener('click', () => {
    const name = playerNameInput.value.trim().toUpperCase();
    if (!name || !game) return;

    localStorage.setItem('sliding-puzzle-player-name', name);

    const state = game.getState();
    addLeaderboardEntry(name, state.time, state.moves, state.gridSize);

    solvedOverlay.classList.add('hidden');
    renderLeaderboard();
    leaderboardOverlay.classList.remove('hidden');
  });

  if (playerNameInput) {
    playerNameInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        btnSubmitScore.click();
      }
    });
  }

  // Leaderboard
  btnLeaderboard.addEventListener('click', () => {
    renderLeaderboard();
    leaderboardOverlay.classList.remove('hidden');
  });

  btnCloseLeaderboard.addEventListener('click', () => {
    leaderboardOverlay.classList.add('hidden');
  });

  leaderboardOverlay.addEventListener('click', (e) => {
    if (e.target === leaderboardOverlay) {
      leaderboardOverlay.classList.add('hidden');
    }
  });

  // ---------------------------------------------------------------
  // Window resize handling
  // ---------------------------------------------------------------
  let resizeTimeout;
  window.addEventListener('resize', () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(() => {
      resizeCanvas();
    }, 150);
  });

  // ---------------------------------------------------------------
  // Bootstrap
  // ---------------------------------------------------------------
  const sampleImage = generateSampleImage();
  resizeCanvas();
  initGame(sampleImage, 3);
})();

