/**
 * main.js - Entry point. Connects PuzzleGame with GestureController
 * and sets up keyboard/mouse fallback controls.
 */
(function () {
  'use strict';

  // ---------------------------------------------------------------
  // Sample image: procedural gradient (generated on canvas)
  // ---------------------------------------------------------------
  function generateSampleImage() {
    const c = document.createElement('canvas');
    c.width = 400;
    c.height = 300;
    const ctx = c.getContext('2d');

    // Multi-color gradient background
    const g1 = ctx.createLinearGradient(0, 0, 400, 300);
    g1.addColorStop(0, '#ff6b6b');
    g1.addColorStop(0.25, '#feca57');
    g1.addColorStop(0.5, '#48dbfb');
    g1.addColorStop(0.75, '#ff9ff3');
    g1.addColorStop(1, '#54a0ff');
    ctx.fillStyle = g1;
    ctx.fillRect(0, 0, 400, 300);

    // Decorative shapes
    ctx.globalAlpha = 0.3;
    const colors = ['#fff', '#2d3436', '#6c5ce7', '#00b894', '#fdcb6e'];
    for (let i = 0; i < 12; i++) {
      ctx.beginPath();
      ctx.arc(
        50 + Math.random() * 300,
        30 + Math.random() * 240,
        15 + Math.random() * 40,
        0,
        Math.PI * 2
      );
      ctx.fillStyle = colors[i % colors.length];
      ctx.fill();
    }

    // Grid pattern
    ctx.globalAlpha = 0.08;
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 1;
    for (let x = 0; x < 400; x += 20) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, 300);
      ctx.stroke();
    }
    for (let y = 0; y < 300; y += 20) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(400, y);
      ctx.stroke();
    }

    // Watermark text
    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 60px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('PUZZLE', 200, 130);
    ctx.font = 'bold 40px sans-serif';
    ctx.fillText('GAME', 200, 190);
    ctx.globalAlpha = 1;

    return c.toDataURL('image/png');
  }

  // ---------------------------------------------------------------
  // DOM references
  // ---------------------------------------------------------------
  const gameCanvas = document.getElementById('game-canvas');
  const videoEl = document.getElementById('webcam');
  const overlayCanvas = document.getElementById('webcam-overlay');

  // HUD elements
  const timerEl = document.getElementById('timer');
  const movesEl = document.getElementById('moves');
  const completionEl = document.getElementById('completion');
  const modeDot = document.getElementById('mode-dot');
  const modeEl = document.getElementById('mode-label');

  // Webcam bar
  const gestureEl = document.getElementById('gesture-label');
  const confidenceEl = document.getElementById('confidence-label');

  // Controls
  const btnNewGame = document.getElementById('btn-new-game');
  const btnCamera = document.getElementById('btn-camera');
  const selectDifficulty = document.getElementById('select-difficulty');
  const btnUpload = document.getElementById('btn-upload');
  const fileInput = document.getElementById('file-input');
  const webcamContainer = document.getElementById('webcam-container');

  // Solved overlay
  const solvedOverlay = document.getElementById('solved-overlay');
  const solvedTimeEl = document.getElementById('solved-time');
  const solvedMovesEl = document.getElementById('solved-moves');
  const btnPlayAgain = document.getElementById('btn-play-again');

  // Snapshot modal
  const snapshotModal = document.getElementById('snapshot-modal');
  const snapshotImg = document.getElementById('snapshot-img');
  const btnCloseSnapshot = document.getElementById('btn-close-snapshot');

  // ---------------------------------------------------------------
  // Canvas sizing
  // ---------------------------------------------------------------
  function resizeCanvas() {
    const container = gameCanvas.parentElement;
    const rect = container.getBoundingClientRect();
    gameCanvas.width = rect.width;
    gameCanvas.height = rect.height;
    if (game && game.imageLoaded) {
      game.resize(rect.width, rect.height);
    }
  }

  // ---------------------------------------------------------------
  // Initialize game
  // ---------------------------------------------------------------
  let game = null;
  let gestureCtrl = null;
  let cameraActive = false;
  let currentImageUrl = null;

  async function initGame(imageUrl, gridSize) {
    if (game) game.destroy();
    solvedOverlay.classList.add('hidden');

    resizeCanvas();

    game = new PuzzleGame('game-canvas', gridSize || 4);

    game.onStateChange = (state) => {
      timerEl.textContent = formatTime(state.time);
      movesEl.textContent = state.moves;
      completionEl.textContent = state.completion + '%';
    };

    game.onWin = (state) => {
      setTimeout(() => {
        solvedTimeEl.textContent = formatTime(state.time);
        solvedMovesEl.textContent = state.moves;
        solvedOverlay.classList.remove('hidden');
      }, 600);
    };

    currentImageUrl = imageUrl;
    await game.loadImage(imageUrl);
  }

  function formatTime(seconds) {
    const m = Math.floor(seconds / 60).toString().padStart(2, '0');
    const s = (seconds % 60).toString().padStart(2, '0');
    return m + ':' + s;
  }

  // ---------------------------------------------------------------
  // Mouse / Keyboard controls
  // ---------------------------------------------------------------
  let isDragging = false;

  function getCanvasPos(e) {
    const rect = gameCanvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left) * (gameCanvas.width / rect.width),
      y: (e.clientY - rect.top) * (gameCanvas.height / rect.height),
    };
  }

  gameCanvas.addEventListener('mousedown', (e) => {
    if (!game || game.won) return;
    const pos = getCanvasPos(e);
    const piece = game.selectPiece(pos.x, pos.y);
    if (piece) {
      isDragging = true;
      gameCanvas.style.cursor = 'grabbing';
    }
  });

  gameCanvas.addEventListener('mousemove', (e) => {
    if (!isDragging || !game) return;
    const pos = getCanvasPos(e);
    game.movePiece(pos.x, pos.y);
  });

  gameCanvas.addEventListener('mouseup', () => {
    if (!isDragging || !game) return;
    isDragging = false;
    gameCanvas.style.cursor = 'crosshair';
    game.releasePiece();
  });

  gameCanvas.addEventListener('mouseleave', () => {
    if (isDragging && game) {
      isDragging = false;
      gameCanvas.style.cursor = 'crosshair';
      game.releasePiece();
    }
  });

  // Touch support
  gameCanvas.addEventListener('touchstart', (e) => {
    e.preventDefault();
    if (!game || game.won) return;
    const touch = e.touches[0];
    const pos = getCanvasPos(touch);
    const piece = game.selectPiece(pos.x, pos.y);
    if (piece) isDragging = true;
  }, { passive: false });

  gameCanvas.addEventListener('touchmove', (e) => {
    e.preventDefault();
    if (!isDragging || !game) return;
    const touch = e.touches[0];
    const pos = getCanvasPos(touch);
    game.movePiece(pos.x, pos.y);
  }, { passive: false });

  gameCanvas.addEventListener('touchend', (e) => {
    e.preventDefault();
    if (!isDragging || !game) return;
    isDragging = false;
    game.releasePiece();
  }, { passive: false });

  // Keyboard
  document.addEventListener('keydown', (e) => {
    if (!game) return;

    switch (e.key.toLowerCase()) {
      case 'r':
        if (game.selectedPiece) {
          game.rotatePiece();
        }
        break;
      case 's':
        takeSnapshot();
        break;
    }
  });

  // ---------------------------------------------------------------
  // Gesture controller integration
  // ---------------------------------------------------------------
  let gestureState = {
    wasGrabbing: false,
    lastGesture: 'none',
  };

  // Smooth cursor interpolation for gesture mode
  let smoothCursor = { x: 0, y: 0 };
  let cursorInitialized = false;
  const LERP = 0.25;

  async function startCamera() {
    if (gestureCtrl) {
      gestureCtrl.destroy();
      gestureCtrl = null;
    }

    webcamContainer.classList.remove('hidden');
    btnCamera.textContent = 'Camera Off';

    try {
      gestureCtrl = new GestureController(videoEl, handleGesture);
      gestureCtrl.setOverlayCanvas(overlayCanvas);
      await gestureCtrl.init();
      cameraActive = true;
      modeEl.textContent = 'Gesture';
      modeDot.classList.add('active');
    } catch (err) {
      console.error('Camera init failed:', err);
      cameraActive = false;
      webcamContainer.classList.add('hidden');
      btnCamera.textContent = 'Camera';
      modeEl.textContent = 'Mouse';
      modeDot.classList.remove('active');
    }
  }

  function stopCamera() {
    if (gestureCtrl) {
      gestureCtrl.destroy();
      gestureCtrl = null;
    }
    cameraActive = false;
    webcamContainer.classList.add('hidden');
    btnCamera.textContent = 'Camera';
    modeEl.textContent = 'Mouse';
    modeDot.classList.remove('active');
    gestureState.wasGrabbing = false;
    gestureState.lastGesture = 'none';
    cursorInitialized = false;
  }

  /**
   * Map gestures to game actions with smooth cursor interpolation.
   * @param {string} gesture
   * @param {number} confidence
   * @param {{ x: number, y: number }|null} handPos
   */
  function handleGesture(gesture, confidence, handPos) {
    if (!game || game.won) return;

    // Update webcam bar UI
    const labels = {
      pinch: 'pinch',
      fist: 'fist',
      open_hand: 'open',
      frame: 'frame',
      none: 'none',
    };
    gestureEl.textContent = labels[gesture] || gesture;
    confidenceEl.textContent = Math.round(confidence * 100) + '%';

    if (!handPos) return;

    // Convert normalized hand position to canvas coordinates
    const rawX = handPos.x * gameCanvas.width;
    const rawY = handPos.y * gameCanvas.height;

    // Smooth cursor with lerp
    if (!cursorInitialized) {
      smoothCursor.x = rawX;
      smoothCursor.y = rawY;
      cursorInitialized = true;
    } else {
      smoothCursor.x += (rawX - smoothCursor.x) * LERP;
      smoothCursor.y += (rawY - smoothCursor.y) * LERP;
    }

    const cx = smoothCursor.x;
    const cy = smoothCursor.y;

    switch (gesture) {
      case 'pinch':
        if (!gestureState.wasGrabbing) {
          const piece = game.selectPiece(cx, cy);
          if (piece) {
            gestureState.wasGrabbing = true;
          }
        } else {
          game.movePiece(cx, cy);
        }
        break;

      case 'open_hand':
        if (gestureState.wasGrabbing) {
          game.releasePiece();
          gestureState.wasGrabbing = false;
        }
        break;

      case 'fist':
        if (gestureState.lastGesture !== 'fist' && game.selectedPiece) {
          game.rotatePiece();
        }
        break;

      case 'frame':
        if (gestureState.lastGesture !== 'frame') {
          takeSnapshot();
        }
        break;
    }

    gestureState.lastGesture = gesture;
  }

  // ---------------------------------------------------------------
  // Snapshot
  // ---------------------------------------------------------------
  function takeSnapshot() {
    if (!game) return;
    const dataUrl = game.takeSnapshot();
    snapshotImg.src = dataUrl;
    snapshotModal.classList.remove('hidden');
  }

  btnCloseSnapshot.addEventListener('click', () => {
    snapshotModal.classList.add('hidden');
  });

  snapshotModal.addEventListener('click', (e) => {
    if (e.target === snapshotModal) {
      snapshotModal.classList.add('hidden');
    }
  });

  // ---------------------------------------------------------------
  // UI controls
  // ---------------------------------------------------------------
  btnNewGame.addEventListener('click', () => {
    const size = parseInt(selectDifficulty.value, 10) || 4;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnCamera.addEventListener('click', () => {
    if (cameraActive) {
      stopCamera();
    } else {
      startCamera();
    }
  });

  selectDifficulty.addEventListener('change', () => {
    const size = parseInt(selectDifficulty.value, 10) || 4;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  btnUpload.addEventListener('click', () => {
    fileInput.click();
  });

  fileInput.addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const size = parseInt(selectDifficulty.value, 10) || 4;
      initGame(ev.target.result, size);
    };
    reader.readAsDataURL(file);
  });

  // Solved overlay: play again
  btnPlayAgain.addEventListener('click', () => {
    solvedOverlay.classList.add('hidden');
    const size = parseInt(selectDifficulty.value, 10) || 4;
    const imgUrl = currentImageUrl || generateSampleImage();
    initGame(imgUrl, size);
  });

  // ---------------------------------------------------------------
  // Window resize handling
  // ---------------------------------------------------------------
  let resizeTimeout;
  window.addEventListener('resize', () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(() => {
      resizeCanvas();
    }, 150);
  });

  // ---------------------------------------------------------------
  // Bootstrap
  // ---------------------------------------------------------------
  const sampleImage = generateSampleImage();
  resizeCanvas();
  initGame(sampleImage, 4);
})();

