.hint-key {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  padding: 2px 6px;
  background: var(--bg-glass);
  border: 1px solid var(--border);
  border-radius: 4px;
  font-size: 10px;
  font-weight: 600;
  color: var(--text-secondary);
}

/* ============================================================
   Solved overlay
   ============================================================ */
.solved-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(9, 9, 11, 0.85);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  z-index: 50;
  animation: fadeIn 0.4s ease;
}

.solved-overlay.hidden {
  display: none;
}

.solved-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  padding: 44px 52px;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: 0 24px 64px rgba(0, 0, 0, 0.5);
  text-align: center;
  animation: slideUp 0.5s ease;
}

.solved-title {
  font-size: 28px;
  font-weight: 700;
  color: var(--accent);
  letter-spacing: -0.5px;
}

.solved-stats {
  display: flex;
  gap: 40px;
}

.solved-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.solved-stat-value {
  font-size: 36px;
  font-weight: 700;
  color: var(--text-primary);
  font-variant-numeric: tabular-nums;
}

.solved-stat-label {
  font-size: 10px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: var(--text-muted);
}

