   ============================================================ */
@media (max-width: 640px) {
  .hud-top {
    top: 8px;
    gap: 4px;
  }

  .hud-pill {
    padding: 4px 10px;
    font-size: 11px;
  }

  .hud-bottom {
    bottom: 8px;
    gap: 4px;
    padding: 6px 8px;
    flex-wrap: wrap;
    justify-content: center;
    border-radius: var(--radius-lg);
    max-width: calc(100vw - 16px);
