  .btn-pill {
    padding: 6px 12px;
    font-size: 11px;
  }

  .select-pill {
    padding: 6px 24px 6px 10px;
    font-size: 11px;
  }

  .webcam-float {
    width: 160px;
    bottom: 70px;
  }

  .keyboard-hints {
    display: none;
  }

  .mode-indicator {
    top: 8px;
    left: 8px;
    font-size: 10px;
    padding: 4px 10px;
  }

  .solved-card {
    padding: 28px 24px;
    margin: 0 16px;
