/* ==========================================================
   Sliding Puzzle – Modern Dark Theme
   Zinc palette · #ccff00 accent · Glassmorphism · JetBrains Mono
   ========================================================== */

@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&display=swap');

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg-base: #09090b;
  --bg-surface: #18181b;
  --bg-elevated: #27272a;
  --bg-glass: rgba(24, 24, 27, 0.8);
  --accent: #ccff00;
  --accent-dim: rgba(204, 255, 0, 0.12);
  --accent-glow: rgba(204, 255, 0, 0.25);
  --text-primary: #fafafa;
  --text-secondary: #a1a1aa;
  --text-muted: #71717a;
  --border: rgba(255, 255, 255, 0.08);
  --success: #22c55e;
  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-full: 9999px;
  --blur: 16px;
  --transition: 0.2s ease;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;
}

html,
body {
  height: 100%;
  overflow: hidden;
  font-family: var(--font-mono);
  background: var(--bg-base);
  color: var(--text-primary);
  -webkit-font-smoothing: antialiased;
}

/* --- App: full viewport --- */
.app {
  position: relative;
  width: 100vw;
  height: 100vh;
  overflow: hidden;
}

/* --- Canvas: full screen --- */
#game-canvas {
  display: block;
  width: 100%;
  height: 100%;
  cursor: pointer;
}

/* ============================================================
   HUD – Floating overlays
   ============================================================ */

/* --- Mode indicator (top-left) --- */
.mode-indicator {
  position: absolute;
  top: 16px;
  left: 16px;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  background: var(--bg-glass);
  backdrop-filter: blur(var(--blur));
  -webkit-backdrop-filter: blur(var(--blur));
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  font-size: 11px;
  font-weight: 500;
  color: var(--text-secondary);
  z-index: 20;
  user-select: none;
}

.mode-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-muted);
  transition: all 0.3s;
}

.mode-dot.active {
  background: var(--accent);
  box-shadow: 0 0 8px var(--accent-glow);
}

/* --- Stats pills (top-center) --- */
.hud-top {
  position: absolute;
  top: 16px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  gap: 6px;
  z-index: 20;
  pointer-events: none;
  user-select: none;
}

.hud-pill {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  background: var(--bg-glass);
  backdrop-filter: blur(var(--blur));
  -webkit-backdrop-filter: blur(var(--blur));
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 500;
  white-space: nowrap;
}

.pill-label {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--text-muted);
}

.pill-value {
  color: var(--text-primary);
  font-weight: 600;
  font-variant-numeric: tabular-nums;
}

/* --- Controls bar (bottom-center) --- */
.hud-bottom {
  position: absolute;
  bottom: 16px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 14px;
  background: var(--bg-glass);
  backdrop-filter: blur(var(--blur));
  -webkit-backdrop-filter: blur(var(--blur));
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  z-index: 20;
}

/* --- Buttons --- */
.btn-pill {
  padding: 8px 18px;
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  background: var(--bg-elevated);
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  transition: all var(--transition);
  white-space: nowrap;
  outline: none;
}

.btn-pill:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: var(--text-muted);
}

.btn-pill:active {
  transform: scale(0.97);
